package main

import (
	"log"
	"net/http"

	"github.com/prometheus/client_golang/prometheus"
)

func init() {
	// Register custom metrics for per-user, per-request tracking
	prometheus.NewGaugeVec(prometheus.GaugeOpts{
		Name: "users",
		Help: "Number of active users",
	}, []string{"user"}).Register()
	prometheus.NewGaugeVec(prometheus.GaugeOpts{
		Name: "requests",
		Help: "Number of requests per user",
	}, []string{"user"}).Register()
}

func main() {
	// Create a new HTTP server with Prometheus metrics exposed
	http.Handle("/metrics", prometheus.Handler())

	log.Println("Starting HTTP server...")

	// Run the HTTP server and listen for incoming connections on port 8080
	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatal(err)
	}
}